mapper.update:
update seckill_coupon
name = #{name}, original_price = #{originalPrice}, seckill_price = #{seckillPrice}, stock = #{stock}, limit_per_user = #{limitPerUser}, status = #{status}, start_time = #{startTime}, end_time = #{endTime}, update_time = #{updateTime}
where id = #{id}

mapper.select:
select id, name, original_price as originalPrice, seckill_price as seckillPrice, stock, limit_per_user as limitPerUser, status, start_time as startTime, end_time as endTime, create_time as createTime, update_time as updateTime
from seckill_coupon
where id = #{id}

select id, name, original_price as originalPrice, seckill_price as seckillPrice, stock, limit_per_user as limitPerUser, status, start_time as startTime, end_time as endTime, create_time as createTime, update_time as updateTime from seckill_coupon
and name like concat('%', #{name}, '%')
order by id desc limit #{page}, #{pageSize}
